  ('locality-7fec267e-moex-00122', 'locality-7fec267e', 'locality-7fec267e-moex-113-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '甲原經乙市政府社會局核定為低收入戶並按月領有低收入生活扶助，嗣後社會局查知甲已將戶籍 遷出乙市，乃以A函通知甲自即日起廢止其低收入戶資格並停止發給生活扶助。甲不服，循序提 起訴願及撤銷訴訟，經行政法院撤銷A函，但社會局僅繼續發給確定判決後之生活扶助。甲依法 應如何救濟？', '["提起再審", "提起課予義務訴訟", "請求行政訴訟強制執行", "提起一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:20+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
